const STORAGE_KEY = "decision-journal-entries";

const initialEntries = [
  {
    id: crypto.randomUUID(),
    title: "Move status updates to weekly batches",
    context: "Daily syncs were expensive and repeated the same information.",
    choice: "Replace daily updates with one weekly written digest.",
    alternatives: ["Keep daily meetings", "Cut updates entirely"],
    confidence: 7,
    reviewDate: "2026-04-20",
    createdAt: "2026-04-09T00:00:00.000Z",
    outcome: "pending",
  },
];

const form = document.querySelector("#decision-form");
const titleInput = document.querySelector("#title");
const contextInput = document.querySelector("#context");
const choiceInput = document.querySelector("#choice");
const alternativesInput = document.querySelector("#alternatives");
const confidenceInput = document.querySelector("#confidence");
const confidenceValue = document.querySelector("#confidence-value");
const reviewDateInput = document.querySelector("#reviewDate");
const statusFilter = document.querySelector("#status-filter");
const entryList = document.querySelector("#entry-list");
const emptyState = document.querySelector("#empty-state");
const template = document.querySelector("#entry-template");

const statTotal = document.querySelector("#stat-total");
const statOpen = document.querySelector("#stat-open");
const statReviewed = document.querySelector("#stat-reviewed");
const statConfidence = document.querySelector("#stat-confidence");

let entries = loadEntries();

confidenceInput.addEventListener("input", () => {
  confidenceValue.textContent = `${confidenceInput.value} / 10`;
});

form.addEventListener("submit", (event) => {
  event.preventDefault();

  const entry = {
    id: crypto.randomUUID(),
    title: titleInput.value.trim(),
    context: contextInput.value.trim(),
    choice: choiceInput.value.trim(),
    alternatives: parseAlternatives(alternativesInput.value),
    confidence: Number(confidenceInput.value),
    reviewDate: reviewDateInput.value || "",
    createdAt: new Date().toISOString(),
    outcome: "pending",
  };

  entries = [entry, ...entries];
  persistEntries();
  form.reset();
  confidenceInput.value = "6";
  confidenceValue.textContent = "6 / 10";
  render();
});

statusFilter.addEventListener("change", render);

entryList.addEventListener("change", (event) => {
  const target = event.target;

  if (!(target instanceof HTMLSelectElement) || !target.matches(".outcome-select")) {
    return;
  }

  const id = target.closest(".entry-card")?.dataset.id;
  entries = entries.map((entry) =>
    entry.id === id ? { ...entry, outcome: target.value } : entry,
  );
  persistEntries();
  render();
});

entryList.addEventListener("click", (event) => {
  const target = event.target;

  if (!(target instanceof HTMLButtonElement) || !target.matches(".delete-button")) {
    return;
  }

  const id = target.closest(".entry-card")?.dataset.id;
  entries = entries.filter((entry) => entry.id !== id);
  persistEntries();
  render();
});

render();

function loadEntries() {
  const raw = localStorage.getItem(STORAGE_KEY);

  if (!raw) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(initialEntries));
    return initialEntries;
  }

  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : initialEntries;
  } catch {
    return initialEntries;
  }
}

function persistEntries() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(entries));
}

function parseAlternatives(value) {
  return value
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
}

function render() {
  const visibleEntries = filterEntries(entries, statusFilter.value);
  entryList.innerHTML = "";

  for (const entry of visibleEntries) {
    const node = template.content.firstElementChild.cloneNode(true);
    node.dataset.id = entry.id;
    node.querySelector(".entry-title").textContent = entry.title;
    node.querySelector(".entry-meta").textContent = buildMeta(entry);
    node.querySelector(".entry-badge").textContent = outcomeLabel(entry.outcome);
    node.querySelector(".entry-context").textContent = entry.context;
    node.querySelector(".entry-choice").textContent = entry.choice;
    node.querySelector(".entry-alternatives").textContent =
      entry.alternatives.length > 0 ? entry.alternatives.join(", ") : "No alternatives recorded.";
    node.querySelector(".outcome-select").value = entry.outcome;
    entryList.appendChild(node);
  }

  emptyState.hidden = visibleEntries.length !== 0;
  updateStats(entries);
}

function filterEntries(allEntries, filter) {
  switch (filter) {
    case "open":
      return allEntries.filter((entry) => entry.outcome === "pending");
    case "reviewed":
      return allEntries.filter((entry) => entry.outcome !== "pending");
    case "wins":
      return allEntries.filter((entry) => entry.outcome === "positive");
    default:
      return allEntries;
  }
}

function updateStats(allEntries) {
  const reviewedCount = allEntries.filter((entry) => entry.outcome !== "pending").length;
  const openCount = allEntries.length - reviewedCount;
  const avgConfidence =
    allEntries.length === 0
      ? 0
      : allEntries.reduce((sum, entry) => sum + Number(entry.confidence), 0) / allEntries.length;

  statTotal.textContent = String(allEntries.length);
  statOpen.textContent = String(openCount);
  statReviewed.textContent = String(reviewedCount);
  statConfidence.textContent = avgConfidence.toFixed(1);
}

function buildMeta(entry) {
  const created = new Date(entry.createdAt).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });

  const review = entry.reviewDate
    ? `Review ${new Date(entry.reviewDate).toLocaleDateString(undefined, {
        month: "short",
        day: "numeric",
      })}`
    : "No review date";

  return `${created} • Confidence ${entry.confidence}/10 • ${review}`;
}

function outcomeLabel(outcome) {
  switch (outcome) {
    case "positive":
      return "Positive";
    case "mixed":
      return "Mixed";
    case "negative":
      return "Negative";
    default:
      return "Pending";
  }
}

:root {
  --bg: #f3efe5;
  --bg-accent: #e2dccf;
  --panel: rgba(255, 252, 246, 0.84);
  --panel-strong: rgba(255, 249, 240, 0.96);
  --text: #172029;
  --muted: #59636d;
  --line: rgba(23, 32, 41, 0.1);
  --accent: #a44f2f;
  --accent-2: #285c63;
  --shadow: 0 18px 60px rgba(35, 28, 24, 0.12);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: "Space Grotesk", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at top left, rgba(164, 79, 47, 0.15), transparent 32%),
    radial-gradient(circle at bottom right, rgba(40, 92, 99, 0.18), transparent 30%),
    linear-gradient(135deg, var(--bg) 0%, #efe6d7 100%);
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  background-image:
    linear-gradient(rgba(23, 32, 41, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(23, 32, 41, 0.04) 1px, transparent 1px);
  background-size: 24px 24px;
  mask-image: linear-gradient(to bottom, rgba(0, 0, 0, 0.7), transparent 85%);
  pointer-events: none;
}

.page-shell {
  position: relative;
  max-width: 1240px;
  margin: 0 auto;
  padding: 48px 20px 80px;
}

.hero {
  max-width: 720px;
  margin-bottom: 28px;
  animation: rise-in 600ms ease-out both;
}

.eyebrow {
  margin: 0 0 10px;
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--accent-2);
}

h1,
h2,
h3,
p {
  margin-top: 0;
}

h1 {
  margin-bottom: 14px;
  font-family: "Instrument Serif", serif;
  font-size: clamp(2.8rem, 8vw, 5.6rem);
  line-height: 0.95;
  letter-spacing: -0.03em;
}

.hero-copy,
.panel-heading p,
.entry-meta,
.entry-context,
.entry-section p,
.compact-filter,
.stat-card span,
.empty-state {
  color: var(--muted);
}

.layout {
  display: grid;
  grid-template-columns: minmax(280px, 420px) minmax(320px, 1fr);
  gap: 22px;
  align-items: start;
}

.panel {
  background: var(--panel);
  border: 1px solid rgba(255, 255, 255, 0.5);
  backdrop-filter: blur(14px);
  border-radius: 28px;
  box-shadow: var(--shadow);
}

.form-panel,
.dashboard-panel {
  padding: 22px;
}

.panel-heading {
  margin-bottom: 20px;
}

.dashboard-heading {
  display: flex;
  gap: 12px;
  align-items: start;
  justify-content: space-between;
}

form,
.entry-list {
  display: grid;
  gap: 16px;
}

label {
  display: grid;
  gap: 8px;
  font-size: 0.95rem;
  font-weight: 500;
}

input,
textarea,
select,
button {
  font: inherit;
}

input,
textarea,
select {
  width: 100%;
  padding: 12px 14px;
  border-radius: 16px;
  border: 1px solid var(--line);
  background: var(--panel-strong);
  color: var(--text);
}

textarea {
  resize: vertical;
  min-height: 110px;
}

.field-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
}

.range-value {
  font-size: 0.88rem;
  color: var(--accent-2);
}

.primary-button,
.ghost-button {
  border: 0;
  border-radius: 999px;
  cursor: pointer;
  transition:
    transform 160ms ease,
    opacity 160ms ease,
    background-color 160ms ease;
}

.primary-button {
  padding: 14px 18px;
  background: linear-gradient(135deg, var(--accent) 0%, #c46d40 100%);
  color: #fff7f1;
  font-weight: 700;
}

.ghost-button {
  padding: 10px 14px;
  background: rgba(23, 32, 41, 0.07);
  color: var(--text);
}

.primary-button:hover,
.ghost-button:hover {
  transform: translateY(-1px);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px;
  margin-bottom: 18px;
}

.stat-card {
  padding: 14px;
  border-radius: 20px;
  background: var(--panel-strong);
  border: 1px solid var(--line);
}

.stat-card strong {
  display: block;
  margin-top: 12px;
  font-size: 1.8rem;
}

.entry-card {
  padding: 18px;
  border-radius: 22px;
  background: rgba(255, 251, 245, 0.92);
  border: 1px solid rgba(23, 32, 41, 0.08);
  animation: rise-in 320ms ease-out both;
}

.entry-topline,
.entry-footer {
  display: flex;
  gap: 12px;
  align-items: start;
  justify-content: space-between;
}

.entry-title {
  margin-bottom: 8px;
  font-size: 1.1rem;
}

.entry-meta {
  font-size: 0.88rem;
}

.entry-badge {
  padding: 7px 10px;
  border-radius: 999px;
  background: rgba(40, 92, 99, 0.1);
  color: var(--accent-2);
  font-size: 0.82rem;
  font-weight: 700;
  white-space: nowrap;
}

.entry-section {
  margin-top: 14px;
}

.section-label {
  display: block;
  margin-bottom: 6px;
  font-size: 0.82rem;
  font-weight: 700;
  letter-spacing: 0.08em;

  text-transform: uppercase;
  color: var(--accent);
}

.entry-footer {
  margin-top: 18px;
  align-items: end;
}

.compact-filter {
  min-width: 140px;
}

.empty-state {
  padding: 34px 18px;
  text-align: center;
  border: 1px dashed rgba(23, 32, 41, 0.18);
  border-radius: 22px;
  background: rgba(255, 252, 246, 0.5);
}

@keyframes rise-in {
  from {
    opacity: 0;
    transform: translateY(16px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 920px) {
  .layout {
    grid-template-columns: 1fr;
  }

  .stats-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 560px) {
  .page-shell {
    padding-inline: 14px;
  }

  .form-panel,
  .dashboard-panel {
    padding: 18px;
  }

  .field-row,
  .dashboard-heading,
  .entry-topline,
  .entry-footer {
    grid-template-columns: 1fr;
    flex-direction: column;
  }

  .stats-grid {
    grid-template-columns: 1fr;
  }
}
